#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

os.makedirs("screens", exist_ok=True)
with open("screens/BatListScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/BatListScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/BatProfileScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/BatProfileScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/OtherScreens.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/OtherScreens.js")

os.makedirs("screens", exist_ok=True)
with open("screens/TrendsScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/TrendsScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/KnockingSessionScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/KnockingSessionScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/HeatmapScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/HeatmapScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/CreateBatScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/CreateBatScreen.js")

print()
print("Run: npx expo start --clear --lan")
print()
print("All screens now use fs() for font scaling.")
print("Changing font size in Settings will now affect every screen.")
